    77→
    78→export interface MemoryMetrics {
    79→  heapUsed: number; // in MB
    80→  heapTotal: number; // in MB
    81→  gcPauses: number[];
    82→}
    83→
    84→export interface FrameVarianceMetrics {
    85→  standardDeviation: number;
    86→  maxDeviation: number;
    87→  droppedFrames: number;
    88→  vsyncMisses: number;
    89→}
    90→
    91→export interface ValidationStatus {
    92→  passed: boolean;
    93→  timingPrecisionMet: boolean;
    94→  performanceAdequate: boolean;
    95→  warnings: string[];
    96→  recommendations: string[];
    97→}
    98→
    99→export class HardwareBenchmark {
   100→  private config: HardwareBenchmarkConfig;
   101→  private clock: PrecisionClock;
   102→  private results: BenchmarkResult[] = [];
   103→
   104→  constructor(config: Partial<HardwareBenchmarkConfig> = {}) {
   105→    this.config = {
   106→      iterations: 1000,
   107→      warmupIterations: 100,
   108→      targetFPS: [60, 120, 144, 240],
   109→      measurementDuration: 5000,
   110→      ...config
   111→    };
   112→
   113→    this.clock = new PrecisionClock();
   114→  }
   115→
   116→  /**
   117→   * Run complete hardware validation suite
   118→   */
   119→  async runFullBenchmark(): Promise<BenchmarkResult> {
   120→    console.log('Starting hardware timing validation...');
   121→
   122→    // Collect system information
   123→    const deviceInfo = await this.collectDeviceInfo();
   124→    const displayInfo = await this.detectDisplayInfo();
   125→    const browserInfo = this.detectBrowserFeatures();
   126→
   127→    // Warm up
   128→    await this.warmup();
   129→
   130→    // Run performance tests
   131→    const fpsMetrics = await this.measureFPS();
   132→    const timingMetrics = await this.measureTimingPrecision();
   133→    const memoryMetrics = await this.measureMemoryUsage();
   134→    const frameVariance = await this.measureFrameVariance();
   135→
   136→    // Validate results
   137→    const validation = this.validateResults({
   138→      fps: fpsMetrics,
   139→      timing: timingMetrics,
   140→      memory: memoryMetrics,
   141→      frameVariance
   142→    });
   143→
   144→    const result: BenchmarkResult = {
   145→      timestamp: Date.now(),
   146→      device: deviceInfo,
   147→      display: displayInfo,
   148→      browser: browserInfo,
   149→      performance: {
   150→        fps: fpsMetrics,
   151→        timing: timingMetrics,
   152→        memory: memoryMetrics,
   153→        frameVariance
   154→      },
   155→      validation
   156→    };
   157→
   158→    this.results.push(result);
   159→    return result;
   160→  }
   161→
   162→  /**
   163→   * Collect device information
   164→   */
   165→  private async collectDeviceInfo(): Promise<DeviceInfo> {
   166→    const info: DeviceInfo = {
   167→      userAgent: navigator.userAgent,
   168→      platform: navigator.platform,
   169→      cores: navigator.hardwareConcurrency || 1,
   170→      memory: 0
   171→    };
   172→
   173→    // Get memory info if available
   174→    if ('deviceMemory' in navigator) {
   175→      info.memory = (navigator as any).deviceMemory;
   176→    }
   177→
   178→    // Try to detect GPU
   179→    const canvas = document.createElement('canvas');
   180→    const gl = canvas.getContext('webgl2') || canvas.getContext('webgl');
   181→    if (gl) {
   182→      const debugInfo = gl.getExtension('WEBGL_debug_renderer_info');
   183→      if (debugInfo) {
   184→        info.gpu = gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL);
   185→      }
   186→    }
   187→
   188→    return info;
   189→  }
   190→
   191→  /**
   192→   * Detect display information
   193→   */
   194→  private async detectDisplayInfo(): Promise<DisplayInfo> {
   195→    const info: DisplayInfo = {
   196→      refreshRate: 60, // Default, will be measured
   197→      resolution: {
   198→        width: window.screen.width,
   199→        height: window.screen.height
   200→      },
   201→      colorDepth: window.screen.colorDepth,
   202→      pixelRatio: window.devicePixelRatio || 1
   203→    };
   204→
   205→    // Measure actual refresh rate
   206→    info.refreshRate = await this.measureRefreshRate();
   207→
   208→    return info;
   209→  }
   210→
   211→  /**
   212→   * Detect browser features
   213→   */
   214→  private detectBrowserFeatures(): BrowserInfo {
   215→    const ua = navigator.userAgent;
   216→    let name = 'Unknown';
   217→    let version = '';
   218→    let engine = '';
   219→
   220→    // Detect browser
   221→    if (ua.includes('Firefox')) {
   222→      name = 'Firefox';
   223→      engine = 'Gecko';
   224→      version = ua.match(/Firefox\/(\d+\.\d+)/)?.[1] || '';
   225→    } else if (ua.includes('Chrome')) {
   226→      name = 'Chrome';
   227→      engine = 'Blink';
   228→      version = ua.match(/Chrome\/(\d+\.\d+)/)?.[1] || '';
   229→    } else if (ua.includes('Safari')) {
   230→      name = 'Safari';
   231→      engine = 'WebKit';
   232→      version = ua.match(/Version\/(\d+\.\d+)/)?.[1] || '';
   233→    }
   234→
   235→    return {
   236→      name,
   237→      version,
   238→      engine,
   239→      features: {
   240→        webGL2: this.hasWebGL2Support(),
   241→        requestVideoFrameCallback: 'requestVideoFrameCallback' in HTMLVideoElement.prototype,
   242→        webAudioAPI: 'AudioContext' in window || 'webkitAudioContext' in window,
   243→        performanceAPI: 'performance' in window && 'now' in performance
   244→      }
   245→    };
   246→  }
   247→
   248→  /**
   249→   * Check for WebGL2 support
   250→   */
   251→  private hasWebGL2Support(): boolean {
   252→    try {
   253→      const canvas = document.createElement('canvas');
   254→      return !!canvas.getContext('webgl2');
   255→    } catch {
   256→      return false;
   257→    }
   258→  }
   259→
   260→  /**
   261→   * Warm up the system
   262→   */
   263→  private async warmup(): Promise<void> {
   264→    console.log('Warming up...');
   265→    
   266→    for (let i = 0; i < this.config.warmupIterations; i++) {
   267→      await this.clock.now();
   268→      await new Promise(resolve => requestAnimationFrame(resolve));
   269→    }
   270→  }
   271→
   272→  /**
   273→   * Measure actual display refresh rate
   274→   */
   275→  private async measureRefreshRate(): Promise<number> {
   276→    const samples: number[] = [];
   277→    let lastTime = performance.now();
   278→
   279→    return new Promise((resolve) => {
   280→      let count = 0;
   281→      const measure = () => {
   282→        const now = performance.now();
   283→        const delta = now - lastTime;
   284→        
   285→        if (count > 0) { // Skip first frame
   286→          samples.push(delta);
   287→        }
   288→        
   289→        lastTime = now;
   290→        count++;
   291→
   292→        if (count < 100) {
   293→          requestAnimationFrame(measure);
   294→        } else {
   295→          const avgDelta = samples.reduce((a, b) => a + b, 0) / samples.length;
   296→          const fps = 1000 / avgDelta;
   297→          resolve(Math.round(fps));
   298→        }
   299→      };
   300→
   301→      requestAnimationFrame(measure);
   302→    });
   303→  }
   304→
   305→  /**
   306→   * Measure FPS performance
   307→   */
   308→  private async measureFPS(): Promise<FPSMetrics> {
   309→    const fpsSamples: number[] = [];
   310→    const startTime = performance.now();
   311→    let frameCount = 0;
   312→    let lastTime = startTime;
   313→
   314→    return new Promise((resolve) => {
   315→      const measureFrame = () => {
   316→        const now = performance.now();
   317→        const delta = now - lastTime;
   318→        
   319→        if (delta > 0) {
   320→          fpsSamples.push(1000 / delta);
   321→        }
   322→        
   323→        lastTime = now;
   324→        frameCount++;
   325→
   326→        if (now - startTime < this.config.measurementDuration) {
   327→          requestAnimationFrame(measureFrame);
   328→        } else {
   329→          // Calculate metrics
   330→          fpsSamples.sort((a, b) => a - b);
   331→          
   332→          resolve({
   333→            average: fpsSamples.reduce((a, b) => a + b, 0) / fpsSamples.length,
   334→            min: fpsSamples[0],
   335→            max: fpsSamples[fpsSamples.length - 1],
   336→            percentiles: {
   337→              p50: fpsSamples[Math.floor(fpsSamples.length * 0.5)],
   338→              p95: fpsSamples[Math.floor(fpsSamples.length * 0.95)],
   339→              p99: fpsSamples[Math.floor(fpsSamples.length * 0.99)]
   340→            }
   341→          });
   342→        }
   343→      };
   344→
   345→      requestAnimationFrame(measureFrame);
   346→    });
   347→  }
   348→
   349→  /**
   350→   * Measure timing precision
   351→   */
   352→  private async measureTimingPrecision(): Promise<TimingMetrics> {
   353→    const clockSamples: number[] = [];
   354→    const jitterSamples: number[] = [];
   355→    
   356→    // Measure clock precision
   357→    for (let i = 0; i < this.config.iterations; i++) {
   358→      const t1 = await this.clock.now();
   359→      const t2 = await this.clock.now();
   360→      const diff = t2.monotonic - t1.monotonic;
   361→      if (diff > 0) {
   362→        clockSamples.push(diff);
   363→      }
   364→    }
   365→
   366→    // Measure stimulus onset jitter
   367→    const targetInterval = 16.67; // 60 FPS target
   368→    let lastFrame = performance.now();
   369→    
   370→    for (let i = 0; i < 100; i++) {
   371→      await new Promise(resolve => requestAnimationFrame(resolve));
   372→      const now = performance.now();
   373→      const actualInterval = now - lastFrame;
   374→      const jitter = Math.abs(actualInterval - targetInterval);
   375→      jitterSamples.push(jitter);
   376→      lastFrame = now;
   377→    }
   378→
   379→    // Calculate response latency (simulated)
   380→    const responseLatencies: number[] = [];
   381→    for (let i = 0; i < 50; i++) {
   382→      const start = performance.now();
   383→      // Simulate minimal processing
   384→      const end = performance.now();
   385→      responseLatencies.push(end - start);
   386→    }
   387→
   388→    return {
   389→      clockPrecision: Math.min(...clockSamples) * 1000, // Convert to microseconds
   390→      stimulusOnsetJitter: jitterSamples.reduce((a, b) => a + b, 0) / jitterSamples.length,
   391→      responseLatency: responseLatencies.reduce((a, b) => a + b, 0) / responseLatencies.length,
   392→      frameTimingAccuracy: this.calculateFrameTimingAccuracy(jitterSamples)
   393→    };
   394→  }
   395→
   396→  /**
   397→   * Calculate frame timing accuracy
   398→   */
   399→  private calculateFrameTimingAccuracy(jitterSamples: number[]): number {
   400→    const targetThreshold = 2; // 2ms threshold
   401→    const withinThreshold = jitterSamples.filter(j => j <= targetThreshold).length;
   402→    return (withinThreshold / jitterSamples.length) * 100;
   403→  }
   404→
   405→  /**
   406→   * Measure memory usage
   407→   */
   408→  private async measureMemoryUsage(): Promise<MemoryMetrics> {
   409→    const metrics: MemoryMetrics = {
   410→      heapUsed: 0,
   411→      heapTotal: 0,
   412→      gcPauses: []
   413→    };
   414→
   415→    // Use Performance Memory API if available
   416→    if ('memory' in performance) {
   417→      const memory = (performance as any).memory;
   418→      metrics.heapUsed = memory.usedJSHeapSize / (1024 * 1024);
   419→      metrics.heapTotal = memory.totalJSHeapSize / (1024 * 1024);
   420→    }
   421→
   422→    // Detect GC pauses by monitoring frame drops
   423→    const gcDetectionDuration = 2000;
   424→    const startTime = performance.now();
   425→    let lastFrame = startTime;
   426→    
   427→    while (performance.now() - startTime < gcDetectionDuration) {
   428→      await new Promise(resolve => requestAnimationFrame(resolve));
   429→      const now = performance.now();
   430→      const frameDuration = now - lastFrame;
   431→      
   432→      // Potential GC pause if frame takes > 50ms
   433→      if (frameDuration > 50) {
   434→        metrics.gcPauses.push(frameDuration);
   435→      }
   436→      
   437→      lastFrame = now;
   438→    }
   439→
   440→    return metrics;
   441→  }
   442→
   443→  /**
   444→   * Measure frame variance
   445→   */
   446→  private async measureFrameVariance(): Promise<FrameVarianceMetrics> {
   447→    const frameTimes: number[] = [];
   448→    const targetFrameTime = 1000 / 60; // 60 FPS target
   449→    let droppedFrames = 0;
   450→    let vsyncMisses = 0;
   451→    let lastTime = performance.now();
   452→
   453→    for (let i = 0; i < 300; i++) { // 5 seconds at 60 FPS
   454→      await new Promise(resolve => requestAnimationFrame(resolve));
   455→      const now = performance.now();
   456→      const frameTime = now - lastTime;
   457→      frameTimes.push(frameTime);
   458→
   459→      // Check for dropped frames (>33ms for 60fps)
   460→      if (frameTime > 33) {
   461→        droppedFrames++;
   462→      }
   463→
   464→      // Check for vsync misses
   465→      if (Math.abs(frameTime - targetFrameTime) > 5) {
   466→        vsyncMisses++;
   467→      }
   468→
   469→      lastTime = now;
   470→    }
   471→
   472→    // Calculate variance metrics
   473→    const mean = frameTimes.reduce((a, b) => a + b, 0) / frameTimes.length;
   474→    const variance = frameTimes.reduce((sum, time) => sum + Math.pow(time - mean, 2), 0) / frameTimes.length;
   475→    const stdDev = Math.sqrt(variance);
   476→    const maxDev = Math.max(...frameTimes.map(t => Math.abs(t - mean)));
   477→
   478→    return {
   479→      standardDeviation: stdDev,
   480→      maxDeviation: maxDev,
   481→      droppedFrames,
   482→      vsyncMisses
   483→    };
   484→  }
   485→
   486→  /**
   487→   * Validate benchmark results
   488→   */
   489→  private validateResults(performance: PerformanceMetrics): ValidationStatus {
   490→    const warnings: string[] = [];
   491→    const recommendations: string[] = [];
   492→
   493→    // Check timing precision
   494→    const timingPrecisionMet = performance.timing.stimulusOnsetJitter <= 2;
   495→    if (!timingPrecisionMet) {
   496→      warnings.push(`Stimulus onset jitter (${performance.timing.stimulusOnsetJitter.toFixed(2)}ms) exceeds 2ms threshold`);
   497→      recommendations.push('Consider using a higher refresh rate display or more powerful hardware');
   498→    }
   499→
   500→    // Check FPS stability
   501→    const fpsStable = performance.fps.percentiles.p95 >= 58; // Allow some margin for 60 FPS
   502→    if (!fpsStable) {
   503→      warnings.push(`Frame rate drops below 60 FPS (95th percentile: ${performance.fps.percentiles.p95.toFixed(1)} FPS)`);
   504→      recommendations.push('Close unnecessary applications and browser tabs');
   505→    }
   506→
   507→    // Check frame variance
   508→    const frameVarianceAcceptable = performance.frameVariance.standardDeviation <= 2;
   509→    if (!frameVarianceAcceptable) {
   510→      warnings.push(`High frame time variance detected (σ = ${performance.frameVariance.standardDeviation.toFixed(2)}ms)`);
   511→      recommendations.push('Disable browser extensions that may interfere with rendering');
   512→    }
   513→
   514→    // Check memory usage
   515→    const memoryAdequate = performance.memory.heapUsed < 100; // 100MB threshold
   516→    if (!memoryAdequate) {
   517→      warnings.push(`High memory usage detected (${performance.memory.heapUsed.toFixed(1)}MB)`);
   518→      recommendations.push('Consider optimizing stimulus preloading strategies');
   519→    }
   520→
   521→    // Check GC pauses
   522→    if (performance.memory.gcPauses.length > 0) {
   523→      warnings.push(`Garbage collection pauses detected (${performance.memory.gcPauses.length} pauses)`);
   524→      recommendations.push('Implement object pooling for frequently created objects');
   525→    }
   526→
   527→    const performanceAdequate = fpsStable && frameVarianceAcceptable && memoryAdequate;
   528→    const passed = timingPrecisionMet && performanceAdequate;
   529→
   530→    return {
   531→      passed,
   532→      timingPrecisionMet,
   533→      performanceAdequate,
   534→      warnings,
   535→      recommendations
   536→    };
   537→  }
   538→
   539→  /**
   540→   * Generate compatibility matrix
   541→   */
   542→  async generateCompatibilityMatrix(): Promise<Map<string, BenchmarkResult>> {
   543→    const matrix = new Map<string, BenchmarkResult>();
   544→    
   545→    // Test different configurations
   546→    const configs = [
   547→      { name: '60Hz', targetFPS: [60] },
   548→      { name: '120Hz', targetFPS: [120] },
   549→      { name: '144Hz', targetFPS: [144] },
   550→      { name: '240Hz', targetFPS: [240] }
   551→    ];
   552→
   553→    for (const config of configs) {
   554→      this.config.targetFPS = config.targetFPS;
   555→      const result = await this.runFullBenchmark();
   556→      matrix.set(config.name, result);
   557→    }
   558→
   559→    return matrix;
   560→  }
   561→
   562→  /**
   563→   * Export results to JSON
   564→   */
   565→  exportResults(): string {
   566→    return JSON.stringify(this.results, null, 2);
   567→  }
   568→
   569→  /**
   570→   * Generate markdown report
   571→   */
   572→  generateReport(): string {
   573→    if (this.results.length === 0) {
   574→      return 'No benchmark results available';
   575→    }
   576→
   577→    const latest = this.results[this.results.length - 1];
   578→    const { device, display, browser, performance, validation } = latest;
   579→
   580→    let report = `# Hardware Timing Validation Report
   581→
   582→## System Information
   583→
   584→### Device
   585→- Platform: ${device.platform}
   586→- CPU Cores: ${device.cores}
   587→- Memory: ${device.memory}GB
   588→- GPU: ${device.gpu || 'Unknown'}
   589→
   590→### Display
   591→- Resolution: ${display.resolution.width}x${display.resolution.height}
   592→- Refresh Rate: ${display.refreshRate}Hz
   593→- Pixel Ratio: ${display.pixelRatio}
   594→
   595→### Browser
   596→- Name: ${browser.name} ${browser.version}
   597→- Engine: ${browser.engine}
   598→- Features:
   599→  - WebGL2: ${browser.features.webGL2 ? '✓' : '✗'}
   600→  - RequestVideoFrameCallback: ${browser.features.requestVideoFrameCallback ? '✓' : '✗'}
   601→  - Web Audio API: ${browser.features.webAudioAPI ? '✓' : '✗'}
   602→
   603→## Performance Results
   604→
   605→### Frame Rate
   606→- Average: ${performance.fps.average.toFixed(1)} FPS
   607→- Min: ${performance.fps.min.toFixed(1)} FPS
   608→- Max: ${performance.fps.max.toFixed(1)} FPS
   609→- 95th Percentile: ${performance.fps.percentiles.p95.toFixed(1)} FPS
   610→
   611→### Timing Precision
   612→- Clock Precision: ${performance.timing.clockPrecision.toFixed(1)}μs
   613→- Stimulus Onset Jitter: ${performance.timing.stimulusOnsetJitter.toFixed(2)}ms
   614→- Response Latency: ${performance.timing.responseLatency.toFixed(2)}ms
   615→- Frame Timing Accuracy: ${performance.timing.frameTimingAccuracy.toFixed(1)}%
   616→
   617→### Frame Variance
   618→- Standard Deviation: ${performance.frameVariance.standardDeviation.toFixed(2)}ms
   619→- Dropped Frames: ${performance.frameVariance.droppedFrames}
   620→- VSync Misses: ${performance.frameVariance.vsyncMisses}
   621→
   622→### Memory Usage
   623→- Heap Used: ${performance.memory.heapUsed.toFixed(1)}MB
   624→- GC Pauses: ${performance.memory.gcPauses.length}
   625→
   626→## Validation Results
   627→
   628→**Status: ${validation.passed ? 'PASSED ✓' : 'FAILED ✗'}**
   629→
   630→- Timing Precision Met: ${validation.timingPrecisionMet ? '✓' : '✗'}
   631→- Performance Adequate: ${validation.performanceAdequate ? '✓' : '✗'}
   632→`;
   633→
   634→    if (validation.warnings.length > 0) {
   635→      report += '\n### Warnings\n';
   636→      validation.warnings.forEach(warning => {
   637→        report += `- ${warning}\n`;
   638→      });
   639→    }
   640→
   641→    if (validation.recommendations.length > 0) {
   642→      report += '\n### Recommendations\n';
   643→      validation.recommendations.forEach(rec => {
   644→        report += `- ${rec}\n`;
   645→      });
   646→    }
   647→
   648→    return report;
   649→  }
   650→}

