/**
 * Hardware Timing Validation Suite
 * 
 * Implements automated hardware benchmark suite to validate <2ms timing precision
 * claims across different devices and configurations.
 */

import { PrecisionClock } from '@psyforge/timing';

export interface HardwareBenchmarkConfig {
  iterations: number;
  warmupIterations: number;
  targetFPS: number[];
  measurementDuration: number; // in milliseconds
}

export interface BenchmarkResult {
  timestamp: number;
  device: DeviceInfo;
  display: DisplayInfo;
  browser: BrowserInfo;
  performance: PerformanceMetrics;
  validation: ValidationStatus;
}

export interface DeviceInfo {
  userAgent: string;
  platform: string;
  cores: number;
  memory: number; // in GB
  gpu?: string;
}

export interface DisplayInfo {
  refreshRate: number;
  resolution: { width: number; height: number };
  colorDepth: number;
  pixelRatio: number;
}

export interface BrowserInfo {
  name: string;
  version: string;
  engine: string;
  features: {
    webGL2: boolean;
    requestVideoFrameCallback: boolean;
    webAudioAPI: boolean;
    performanceAPI: boolean;
  };
}

export interface PerformanceMetrics {
  fps: FPSMetrics;
  timing: TimingMetrics;
  memory: MemoryMetrics;
  frameVariance: FrameVarianceMetrics;
}

export interface FPSMetrics {
  average: number;
  min: number;
  max: number;
  percentiles: {
    p50: number;
    p95: number;
    p99: number;
  };
}

export interface TimingMetrics {
  clockPrecision: number; // in microseconds
  stimulusOnsetJitter: number; // in milliseconds
  responseLatency: number; // in milliseconds
  frameTimingAccuracy: number; // percentage
}

export interface MemoryMetrics {
  heapUsed: number; // in MB
  heapTotal: number; // in MB
  gcPauses: number[];
}

export interface FrameVarianceMetrics {
  standardDeviation: number;
  maxDeviation: number;
  droppedFrames: number;
  vsyncMisses: number;
}

export interface ValidationStatus {
  passed: boolean;
  timingPrecisionMet: boolean;
  performanceAdequate: boolean;
  warnings: string[];
  recommendations: string[];
}

export class HardwareBenchmark {
  private config: HardwareBenchmarkConfig;
  private clock: PrecisionClock;
  private results: BenchmarkResult[] = [];

  constructor(config: Partial<HardwareBenchmarkConfig> = {}) {
    this.config = {
      iterations: 1000,
      warmupIterations: 100,
      targetFPS: [60, 120, 144, 240],
      measurementDuration: 5000,
      ...config
    };

    this.clock = new PrecisionClock();
  }

  /**
   * Run complete hardware validation suite
   */
  async runFullBenchmark(): Promise<BenchmarkResult> {
    console.log('Starting hardware timing validation...');

    // Collect system information
    const deviceInfo = await this.collectDeviceInfo();
    const displayInfo = await this.detectDisplayInfo();
    const browserInfo = this.detectBrowserFeatures();

    // Warm up
    await this.warmup();

    // Run performance tests
    const fpsMetrics = await this.measureFPS();
    const timingMetrics = await this.measureTimingPrecision();
    const memoryMetrics = await this.measureMemoryUsage();
    const frameVariance = await this.measureFrameVariance();

    // Validate results
    const validation = this.validateResults({
      fps: fpsMetrics,
      timing: timingMetrics,
      memory: memoryMetrics,
      frameVariance
    });

    const result: BenchmarkResult = {
      timestamp: Date.now(),
      device: deviceInfo,
      display: displayInfo,
      browser: browserInfo,
      performance: {
        fps: fpsMetrics,
        timing: timingMetrics,
        memory: memoryMetrics,
        frameVariance
      },
      validation
    };

    this.results.push(result);
    return result;
  }

  /**
   * Collect device information
   */
  private async collectDeviceInfo(): Promise<DeviceInfo> {
    const info: DeviceInfo = {
      userAgent: navigator.userAgent,
      platform: navigator.platform,
      cores: navigator.hardwareConcurrency || 1,
      memory: 0
    };

    // Get memory info if available
    if ('deviceMemory' in navigator) {
      info.memory = (navigator as any).deviceMemory;
    }

    // Try to detect GPU
    const canvas = document.createElement('canvas');
    const gl = canvas.getContext('webgl2') || canvas.getContext('webgl');
    if (gl) {
      const debugInfo = gl.getExtension('WEBGL_debug_renderer_info');
      if (debugInfo) {
        info.gpu = gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL);
      }
    }

    return info;
  }

  /**
   * Detect display information
   */
  private async detectDisplayInfo(): Promise<DisplayInfo> {
    const info: DisplayInfo = {
      refreshRate: 60, // Default, will be measured
      resolution: {
        width: window.screen.width,
        height: window.screen.height
      },
      colorDepth: window.screen.colorDepth,
      pixelRatio: window.devicePixelRatio || 1
    };

    // Measure actual refresh rate
    info.refreshRate = await this.measureRefreshRate();

    return info;
  }

  /**
   * Detect browser features
   */
  private detectBrowserFeatures(): BrowserInfo {
    const ua = navigator.userAgent;
    let name = 'Unknown';
    let version = '';
    let engine = '';

    // Detect browser
    if (ua.includes('Firefox')) {
      name = 'Firefox';
      engine = 'Gecko';
      version = ua.match(/Firefox\/(\d+\.\d+)/)?.[1] || '';
    } else if (ua.includes('Chrome')) {
      name = 'Chrome';
      engine = 'Blink';
      version = ua.match(/Chrome\/(\d+\.\d+)/)?.[1] || '';
    } else if (ua.includes('Safari')) {
      name = 'Safari';
      engine = 'WebKit';
      version = ua.match(/Version\/(\d+\.\d+)/)?.[1] || '';
    }

    return {
      name,
      version,
      engine,
      features: {
        webGL2: this.hasWebGL2Support(),
        requestVideoFrameCallback: 'requestVideoFrameCallback' in HTMLVideoElement.prototype,
        webAudioAPI: 'AudioContext' in window || 'webkitAudioContext' in window,
        performanceAPI: 'performance' in window && 'now' in performance
      }
    };
  }

  /**
   * Check for WebGL2 support
   */
  private hasWebGL2Support(): boolean {
    try {
      const canvas = document.createElement('canvas');
      return !!canvas.getContext('webgl2');
    } catch {
      return false;
    }
  }

  /**
   * Warm up the system
   */
  private async warmup(): Promise<void> {
    console.log('Warming up...');

    for (let i = 0; i < this.config.warmupIterations; i++) {
      await this.clock.now();
      await new Promise(resolve => requestAnimationFrame(resolve));
    }
  }

  /**
   * Measure actual display refresh rate
   */
  private async measureRefreshRate(): Promise<number> {
    const samples: number[] = [];
    let lastTime = performance.now();

    return new Promise((resolve) => {
      let count = 0;
      const measure = () => {
        const now = performance.now();
        const delta = now - lastTime;

        if (count > 0) { // Skip first frame
          samples.push(delta);
        }

        lastTime = now;
        count++;

        if (count < 100) {
          requestAnimationFrame(measure);
        } else {
          const avgDelta = samples.reduce((a, b) => a + b, 0) / samples.length;
          const fps = 1000 / avgDelta;
          resolve(Math.round(fps));
        }
      };

      requestAnimationFrame(measure);
    });
  }

  /**
   * Measure FPS performance
   */
  private async measureFPS(): Promise<FPSMetrics> {
    const fpsSamples: number[] = [];
    const startTime = performance.now();
    let frameCount = 0;
    let lastTime = startTime;

    return new Promise((resolve) => {
      const measureFrame = () => {
        const now = performance.now();
        const delta = now - lastTime;

        if (delta > 0) {
          fpsSamples.push(1000 / delta);
        }

        lastTime = now;
        frameCount++;

        if (now - startTime < this.config.measurementDuration) {
          requestAnimationFrame(measureFrame);
        } else {
          // Calculate metrics
          fpsSamples.sort((a, b) => a - b);

          resolve({
            average: fpsSamples.reduce((a, b) => a + b, 0) / fpsSamples.length,
            min: fpsSamples[0],
            max: fpsSamples[fpsSamples.length - 1],
            percentiles: {
              p50: fpsSamples[Math.floor(fpsSamples.length * 0.5)],
              p95: fpsSamples[Math.floor(fpsSamples.length * 0.95)],
              p99: fpsSamples[Math.floor(fpsSamples.length * 0.99)]
            }
          });
        }
      };

      requestAnimationFrame(measureFrame);
    });
  }

  /**
   * Measure timing precision
   */
  private async measureTimingPrecision(): Promise<TimingMetrics> {
    const clockSamples: number[] = [];
    const jitterSamples: number[] = [];

    // Measure clock precision
    for (let i = 0; i < this.config.iterations; i++) {
      const t1 = await this.clock.now();
      const t2 = await this.clock.now();
      const diff = t2.monotonic - t1.monotonic;
      if (diff > 0) {
        clockSamples.push(diff);
      }
    }

    // Measure stimulus onset jitter
    const targetInterval = 16.67; // 60 FPS target
    let lastFrame = performance.now();

    for (let i = 0; i < 100; i++) {
      await new Promise(resolve => requestAnimationFrame(resolve));
      const now = performance.now();
      const actualInterval = now - lastFrame;
      const jitter = Math.abs(actualInterval - targetInterval);
      jitterSamples.push(jitter);
      lastFrame = now;
    }

    // Calculate response latency (simulated)
    const responseLatencies: number[] = [];
    for (let i = 0; i < 50; i++) {
      const start = performance.now();
      // Simulate minimal processing
      const end = performance.now();
      responseLatencies.push(end - start);
    }

    return {
      clockPrecision: Math.min(...clockSamples) * 1000, // Convert to microseconds
      stimulusOnsetJitter: jitterSamples.reduce((a, b) => a + b, 0) / jitterSamples.length,
      responseLatency: responseLatencies.reduce((a, b) => a + b, 0) / responseLatencies.length,
      frameTimingAccuracy: this.calculateFrameTimingAccuracy(jitterSamples)
    };
  }

  /**
   * Calculate frame timing accuracy
   */
  private calculateFrameTimingAccuracy(jitterSamples: number[]): number {
    const targetThreshold = 2; // 2ms threshold
    const withinThreshold = jitterSamples.filter(j => j <= targetThreshold).length;
    return (withinThreshold / jitterSamples.length) * 100;
  }

  /**
   * Measure memory usage
   */
  private async measureMemoryUsage(): Promise<MemoryMetrics> {
    const metrics: MemoryMetrics = {
      heapUsed: 0,
      heapTotal: 0,
      gcPauses: []
    };

    // Use Performance Memory API if available
    if ('memory' in performance) {
      const memory = (performance as any).memory;
      metrics.heapUsed = memory.usedJSHeapSize / (1024 * 1024);
      metrics.heapTotal = memory.totalJSHeapSize / (1024 * 1024);
    }

    // Detect GC pauses by monitoring frame drops
    const gcDetectionDuration = 2000;
    const startTime = performance.now();
    let lastFrame = startTime;

    while (performance.now() - startTime < gcDetectionDuration) {
      await new Promise(resolve => requestAnimationFrame(resolve));
      const now = performance.now();
      const frameDuration = now - lastFrame;

      // Potential GC pause if frame takes > 50ms
      if (frameDuration > 50) {
        metrics.gcPauses.push(frameDuration);
      }

      lastFrame = now;
    }

    return metrics;
  }

  /**
   * Measure frame variance
   */
  private async measureFrameVariance(): Promise<FrameVarianceMetrics> {
    const frameTimes: number[] = [];
    const targetFrameTime = 1000 / 60; // 60 FPS target
    let droppedFrames = 0;
    let vsyncMisses = 0;
    let lastTime = performance.now();

    for (let i = 0; i < 300; i++) { // 5 seconds at 60 FPS
      await new Promise(resolve => requestAnimationFrame(resolve));
      const now = performance.now();
      const frameTime = now - lastTime;
      frameTimes.push(frameTime);

      // Check for dropped frames (>33ms for 60fps)
      if (frameTime > 33) {
        droppedFrames++;
      }

      // Check for vsync misses
      if (Math.abs(frameTime - targetFrameTime) > 5) {
        vsyncMisses++;
      }

      lastTime = now;
    }

    // Calculate variance metrics
    const mean = frameTimes.reduce((a, b) => a + b, 0) / frameTimes.length;
    const variance = frameTimes.reduce((sum, time) => sum + Math.pow(time - mean, 2), 0) / frameTimes.length;
    const stdDev = Math.sqrt(variance);
    const maxDev = Math.max(...frameTimes.map(t => Math.abs(t - mean)));

    return {
      standardDeviation: stdDev,
      maxDeviation: maxDev,
      droppedFrames,
      vsyncMisses
    };
  }

  /**
   * Validate benchmark results
   */
  private validateResults(performance: PerformanceMetrics): ValidationStatus {
    const warnings: string[] = [];
    const recommendations: string[] = [];

    // Check timing precision
    const timingPrecisionMet = performance.timing.stimulusOnsetJitter <= 2;
    if (!timingPrecisionMet) {
      warnings.push(`Stimulus onset jitter (${performance.timing.stimulusOnsetJitter.toFixed(2)}ms) exceeds 2ms threshold`);
      recommendations.push('Consider using a higher refresh rate display or more powerful hardware');
    }

    // Check FPS stability
    const fpsStable = performance.fps.percentiles.p95 >= 58; // Allow some margin for 60 FPS
    if (!fpsStable) {
      warnings.push(`Frame rate drops below 60 FPS (95th percentile: ${performance.fps.percentiles.p95.toFixed(1)} FPS)`);
      recommendations.push('Close unnecessary applications and browser tabs');
    }

    // Check frame variance
    const frameVarianceAcceptable = performance.frameVariance.standardDeviation <= 2;
    if (!frameVarianceAcceptable) {
      warnings.push(`High frame time variance detected (σ = ${performance.frameVariance.standardDeviation.toFixed(2)}ms)`);
      recommendations.push('Disable browser extensions that may interfere with rendering');
    }

    // Check memory usage
    const memoryAdequate = performance.memory.heapUsed < 100; // 100MB threshold
    if (!memoryAdequate) {
      warnings.push(`High memory usage detected (${performance.memory.heapUsed.toFixed(1)}MB)`);
      recommendations.push('Consider optimizing stimulus preloading strategies');
    }

    // Check GC pauses
    if (performance.memory.gcPauses.length > 0) {
      warnings.push(`Garbage collection pauses detected (${performance.memory.gcPauses.length} pauses)`);
      recommendations.push('Implement object pooling for frequently created objects');
    }

    const performanceAdequate = fpsStable && frameVarianceAcceptable && memoryAdequate;
    const passed = timingPrecisionMet && performanceAdequate;

    return {
      passed,
      timingPrecisionMet,
      performanceAdequate,
      warnings,
      recommendations
    };
  }

  /**
   * Generate compatibility matrix
   */
  async generateCompatibilityMatrix(): Promise<Map<string, BenchmarkResult>> {
    const matrix = new Map<string, BenchmarkResult>();

    // Test different configurations
    const configs = [
      { name: '60Hz', targetFPS: [60] },
      { name: '120Hz', targetFPS: [120] },
      { name: '144Hz', targetFPS: [144] },
      { name: '240Hz', targetFPS: [240] }
    ];

    for (const config of configs) {
      this.config.targetFPS = config.targetFPS;
      const result = await this.runFullBenchmark();
      matrix.set(config.name, result);
    }

    return matrix;
  }

  /**
   * Export results to JSON
   */
  exportResults(): string {
    return JSON.stringify(this.results, null, 2);
  }

  /**
   * Generate markdown report
   */
  generateReport(): string {
    if (this.results.length === 0) {
      return 'No benchmark results available';
    }

    const latest = this.results[this.results.length - 1];
    const { device, display, browser, performance, validation } = latest;

    let report = `# Hardware Timing Validation Report

## System Information

### Device
- Platform: ${device.platform}
- CPU Cores: ${device.cores}
- Memory: ${device.memory}GB
- GPU: ${device.gpu || 'Unknown'}

### Display
- Resolution: ${display.resolution.width}x${display.resolution.height}
- Refresh Rate: ${display.refreshRate}Hz
- Pixel Ratio: ${display.pixelRatio}

### Browser
- Name: ${browser.name} ${browser.version}
- Engine: ${browser.engine}
- Features:
  - WebGL2: ${browser.features.webGL2 ? '✓' : '✗'}
  - RequestVideoFrameCallback: ${browser.features.requestVideoFrameCallback ? '✓' : '✗'}
  - Web Audio API: ${browser.features.webAudioAPI ? '✓' : '✗'}

## Performance Results

### Frame Rate
- Average: ${performance.fps.average.toFixed(1)} FPS
- Min: ${performance.fps.min.toFixed(1)} FPS
- Max: ${performance.fps.max.toFixed(1)} FPS
- 95th Percentile: ${performance.fps.percentiles.p95.toFixed(1)} FPS

### Timing Precision
- Clock Precision: ${performance.timing.clockPrecision.toFixed(1)}μs
- Stimulus Onset Jitter: ${performance.timing.stimulusOnsetJitter.toFixed(2)}ms
- Response Latency: ${performance.timing.responseLatency.toFixed(2)}ms
- Frame Timing Accuracy: ${performance.timing.frameTimingAccuracy.toFixed(1)}%

### Frame Variance
- Standard Deviation: ${performance.frameVariance.standardDeviation.toFixed(2)}ms
- Dropped Frames: ${performance.frameVariance.droppedFrames}
- VSync Misses: ${performance.frameVariance.vsyncMisses}

### Memory Usage
- Heap Used: ${performance.memory.heapUsed.toFixed(1)}MB
- GC Pauses: ${performance.memory.gcPauses.length}

## Validation Results

**Status: ${validation.passed ? 'PASSED ✓' : 'FAILED ✗'}**

- Timing Precision Met: ${validation.timingPrecisionMet ? '✓' : '✗'}
- Performance Adequate: ${validation.performanceAdequate ? '✓' : '✗'}
`;

    if (validation.warnings.length > 0) {
      report += '\n### Warnings\n';
      validation.warnings.forEach(warning => {
        report += `- ${warning}\n`;
      });
    }

    if (validation.recommendations.length > 0) {
      report += '\n### Recommendations\n';
      validation.recommendations.forEach(rec => {
        report += `- ${rec}\n`;
      });
    }

    return report;
  }
}

