/**
 * RequestVideoFrameCallback Validation
 * 
 * Tests and validates the requestVideoFrameCallback API for precise
 * frame-level timing control in supported browsers.
 */

export interface VideoFrameMetadata {
  presentationTime: DOMHighResTimeStamp;
  expectedDisplayTime: DOMHighResTimeStamp;
  width: number;
  height: number;
  mediaTime: number;
  presentedFrames: number;
  processingDuration?: number;
  captureTime?: DOMHighResTimeStamp;
  receiveTime?: DOMHighResTimeStamp;
  rtpTimestamp?: number;
}

export interface VideoFrameValidationResult {
  supported: boolean;
  accuracy: number; // in milliseconds
  consistency: number; // percentage
  framePrediction: {
    averageError: number;
    maxError: number;
    reliability: number; // percentage
  };
  recommendations: string[];
}

export class VideoFrameValidator {
  private video: HTMLVideoElement | null = null;
  private canvas: HTMLCanvasElement | null = null;
  private frameTimings: Array<{
    predicted: number;
    actual: number;
    error: number;
  }> = [];

  /**
   * Check if requestVideoFrameCallback is supported
   */
  static isSupported(): boolean {
    return 'requestVideoFrameCallback' in HTMLVideoElement.prototype;
  }

  /**
   * Run video frame timing validation
   */
  async validate(): Promise<VideoFrameValidationResult> {
    if (!VideoFrameValidator.isSupported()) {
      return {
        supported: false,
        accuracy: Infinity,
        consistency: 0,
        framePrediction: {
          averageError: Infinity,
          maxError: Infinity,
          reliability: 0
        },
        recommendations: [
          'Browser does not support requestVideoFrameCallback API',
          'Consider using Chrome 83+ or other Chromium-based browsers',
          'Fallback to requestAnimationFrame for frame timing'
        ]
      };
    }

    // Create test video element
    this.video = document.createElement('video');
    this.canvas = document.createElement('canvas');

    // Generate test video pattern
    await this.setupTestVideo();

    // Run timing tests
    const timingResults = await this.measureFrameTiming();

    // Clean up
    this.cleanup();

    return this.analyzeResults(timingResults);
  }

  /**
   * Setup test video with precise timing pattern
   */
  private async setupTestVideo(): Promise<void> {
    if (!this.video || !this.canvas) return;

    // Create a test video pattern programmatically
    const ctx = this.canvas.getContext('2d');
    if (!ctx) throw new Error('Failed to get canvas context');

    this.canvas.width = 320;
    this.canvas.height = 240;

    // Generate frames with timing markers
    const frames: Blob[] = [];
    const frameRate = 60;
    const duration = 2; // 2 seconds
    const totalFrames = frameRate * duration;

    for (let i = 0; i < totalFrames; i++) {
      // Clear canvas
      ctx.fillStyle = 'black';
      ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

      // Draw frame number
      ctx.fillStyle = 'white';
      ctx.font = '48px monospace';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(i.toString(), this.canvas.width / 2, this.canvas.height / 2);

      // Draw timing marker
      const markerSize = 20;
      const markerX = (i % 10) * (this.canvas.width / 10);
      ctx.fillStyle = 'red';
      ctx.fillRect(markerX, 0, markerSize, markerSize);

      // Capture frame
      const blob = await new Promise<Blob>((resolve) => {
        this.canvas!.toBlob((blob) => resolve(blob!), 'image/webp', 0.9);
      });
      frames.push(blob);
    }

    // Create video from frames using MediaRecorder
    const stream = this.canvas.captureStream(frameRate);
    const recorder = new MediaRecorder(stream, {
      mimeType: 'video/webm;codecs=vp9',
      videoBitsPerSecond: 5000000
    });

    const chunks: Blob[] = [];
    recorder.ondataavailable = (e) => chunks.push(e.data);

    await new Promise<void>((resolve) => {
      recorder.onstop = () => {
        const videoBlob = new Blob(chunks, { type: 'video/webm' });
        const videoUrl = URL.createObjectURL(videoBlob);
        this.video!.src = videoUrl;
        resolve();
      };

      // Play frames
      recorder.start();
      let frameIndex = 0;

      const drawFrame = () => {
        if (frameIndex < frames.length) {
          // Draw frame
          const img = new Image();
          img.onload = () => {
            ctx.drawImage(img, 0, 0);
            frameIndex++;
            setTimeout(drawFrame, 1000 / frameRate);
          };
          img.src = URL.createObjectURL(frames[frameIndex]);
        } else {
          recorder.stop();
        }
      };

      drawFrame();
    });

    // Wait for video to be ready
    await new Promise<void>((resolve) => {
      this.video!.onloadedmetadata = () => resolve();
    });
  }

  /**
   * Measure frame timing accuracy
   */
  private async measureFrameTiming(): Promise<Array<{
    predicted: number;
    actual: number;
    error: number;
  }>> {
    if (!this.video) return [];

    const measurements: Array<{
      predicted: number;
      actual: number;
      error: number;
    }> = [];

    let frameCount = 0;
    let lastPresentationTime = 0;

    await new Promise<void>((resolve) => {
      const processFrame = (now: DOMHighResTimeStamp, metadata: VideoFrameMetadata) => {
        if (frameCount > 0) {
          const actualInterval = metadata.presentationTime - lastPresentationTime;
          const predictedInterval = metadata.expectedDisplayTime - metadata.presentationTime;
          const error = Math.abs(actualInterval - (1000 / 60)); // Assuming 60fps

          measurements.push({
            predicted: predictedInterval,
            actual: actualInterval,
            error
          });
        }

        lastPresentationTime = metadata.presentationTime;
        frameCount++;

        // Continue for 100 frames
        if (frameCount < 100) {
          this.video!.requestVideoFrameCallback(processFrame);
        } else {
          resolve();
        }
      };

      // Start playback
      this.video.play();
      this.video.requestVideoFrameCallback(processFrame);
    });

    return measurements;
  }

  /**
   * Analyze timing results
   */
  private analyzeResults(timings: Array<{
    predicted: number;
    actual: number;
    error: number;
  }>): VideoFrameValidationResult {
    if (timings.length === 0) {
      return {
        supported: true,
        accuracy: Infinity,
        consistency: 0,
        framePrediction: {
          averageError: Infinity,
          maxError: Infinity,
          reliability: 0
        },
        recommendations: ['No timing data collected']
      };
    }

    // Calculate accuracy metrics
    const errors = timings.map(t => t.error);
    const averageError = errors.reduce((a, b) => a + b, 0) / errors.length;
    const maxError = Math.max(...errors);

    // Calculate consistency (percentage of frames within 2ms threshold)
    const withinThreshold = errors.filter(e => e <= 2).length;
    const consistency = (withinThreshold / errors.length) * 100;

    // Calculate prediction reliability
    const predictionErrors = timings.map(t => Math.abs(t.predicted - t.actual));
    const avgPredictionError = predictionErrors.reduce((a, b) => a + b, 0) / predictionErrors.length;
    const maxPredictionError = Math.max(...predictionErrors);
    const reliablePredictions = predictionErrors.filter(e => e <= 1).length;
    const predictionReliability = (reliablePredictions / predictionErrors.length) * 100;

    // Generate recommendations
    const recommendations: string[] = [];

    if (consistency < 95) {
      recommendations.push('Frame timing consistency below 95%, consider optimizing rendering pipeline');
    }

    if (maxError > 5) {
      recommendations.push('Maximum frame timing error exceeds 5ms, may impact precise timing requirements');
    }

    if (predictionReliability < 90) {
      recommendations.push('Frame prediction reliability below 90%, expectedDisplayTime may not be accurate');
    }

    if (recommendations.length === 0) {
      recommendations.push('Video frame timing meets precision requirements');
    }

    return {
      supported: true,
      accuracy: averageError,
      consistency,
      framePrediction: {
        averageError: avgPredictionError,
        maxError: maxPredictionError,
        reliability: predictionReliability
      },
      recommendations
    };
  }

  /**
   * Clean up resources
   */
  private cleanup(): void {
    if (this.video) {
      this.video.pause();
      this.video.src = '';
      this.video = null;
    }

    if (this.canvas) {
      this.canvas = null;
    }

    this.frameTimings = [];
  }

  /**
   * Generate report
   */
  generateReport(result: VideoFrameValidationResult): string {
    let report = `# RequestVideoFrameCallback Validation Report

## Support Status
- API Supported: ${result.supported ? '✓' : '✗'}

`;

    if (result.supported) {
      report += `## Timing Accuracy
- Average Error: ${result.accuracy.toFixed(2)}ms
- Consistency: ${result.consistency.toFixed(1)}% of frames within 2ms threshold

## Frame Prediction
- Average Prediction Error: ${result.framePrediction.averageError.toFixed(2)}ms
- Maximum Prediction Error: ${result.framePrediction.maxError.toFixed(2)}ms
- Prediction Reliability: ${result.framePrediction.reliability.toFixed(1)}%

`;
    }

    report += `## Recommendations
${result.recommendations.map(r => `- ${r}`).join('\n')}
`;

    return report;
  }
}

