     1→/**
     2→ * CI Integration for Hardware Timing Validation
     3→ * 
     4→ * Enables automated timing validation in continuous integration pipelines
     5→ * with performance regression detection.
     6→ */
     7→
     8→import { HardwareBenchmark, BenchmarkResult } from './hardware-benchmark';
     9→import { VideoFrameValidator, VideoFrameValidationResult } from './video-frame-validation';
    10→
    11→export interface CIValidationConfig {
    12→  baselineFile?: string;
    13→  thresholds: {
    14→    timingPrecision: number; // max jitter in ms
    15→    fpsMinimum: number;
    16→    frameVariance: number; // max std deviation in ms
    17→    memoryLimit: number; // max heap usage in MB
    18→  };
    19→  exitOnFailure: boolean;
    20→  generateArtifacts: boolean;
    21→  outputFormat: 'json' | 'junit' | 'markdown';
    22→}
    23→
    24→export interface CIValidationResult {
    25→  passed: boolean;
    26→  timestamp: number;
    27→  environment: {
    28→    ci: boolean;
    29→    platform: string;
    30→    node: string;
    31→  };
    32→  benchmarkResult: BenchmarkResult;
    33→  videoFrameResult: VideoFrameValidationResult;
    34→  regressions: RegressionReport[];
    35→  artifacts: {
    36→    report?: string;
    37→    data?: string;
    38→    charts?: string;
    39→  };
    40→}
    41→
    42→export interface RegressionReport {
    43→  metric: string;
    44→  baseline: number;
    45→  current: number;
    46→  change: number; // percentage
    47→  threshold: number;
    48→  severity: 'warning' | 'error';
    49→}
    50→
    51→export interface BaselineData {
    52→  version: string;
    53→  timestamp: number;
    54→  environment: string;
    55→  metrics: {
    56→    timingPrecision: number;
    57→    avgFPS: number;
    58→    frameVariance: number;
    59→    memoryUsage: number;
    60→  };
    61→}
    62→
    63→export class CIValidator {
    64→  private config: CIValidationConfig;
    65→  private baseline: BaselineData | null = null;
    66→
    67→  constructor(config: Partial<CIValidationConfig> = {}) {
    68→    this.config = {
    69→      thresholds: {
    70→        timingPrecision: 2,
    71→        fpsMinimum: 58,
    72→        frameVariance: 2,
    73→        memoryLimit: 100
    74→      },
    75→      exitOnFailure: true,
    76→      generateArtifacts: true,
    77→      outputFormat: 'json',
    78→      ...config
    79→    };
    80→  }
    81→
    82→  /**
    83→   * Run full CI validation suite
    84→   */
    85→  async runValidation(): Promise<CIValidationResult> {
    86→    console.log('🚀 Starting CI timing validation...\n');
    87→
    88→    // Load baseline if available
    89→    if (this.config.baselineFile) {
    90→      await this.loadBaseline(this.config.baselineFile);
    91→    }
    92→
    93→    // Run hardware benchmark
    94→    const benchmark = new HardwareBenchmark();
    95→    const benchmarkResult = await benchmark.runFullBenchmark();
    96→
    97→    // Run video frame validation
    98→    const videoValidator = new VideoFrameValidator();
    99→    const videoFrameResult = await videoValidator.validate();
   100→
   101→    // Detect regressions
   102→    const regressions = this.detectRegressions(benchmarkResult);
   103→
   104→    // Determine overall pass/fail
   105→    const passed = this.evaluateResults(benchmarkResult, videoFrameResult, regressions);
   106→
   107→    // Generate artifacts
   108→    const artifacts: CIValidationResult['artifacts'] = {};
   109→    if (this.config.generateArtifacts) {
   110→      artifacts.report = this.generateReport(benchmarkResult, videoFrameResult, regressions);
   111→      artifacts.data = JSON.stringify({ benchmarkResult, videoFrameResult }, null, 2);
   112→      
   113→      if (this.config.outputFormat === 'markdown') {
   114→        artifacts.charts = this.generateCharts(benchmarkResult);
   115→      }
   116→    }
   117→
   118→    const result: CIValidationResult = {
   119→      passed,
   120→      timestamp: Date.now(),
   121→      environment: {
   122→        ci: !!process.env.CI,
   123→        platform: process.platform,
   124→        node: process.version
   125→      },
   126→      benchmarkResult,
   127→      videoFrameResult,
   128→      regressions,
   129→      artifacts
   130→    };
   131→
   132→    // Output results
   133→    this.outputResults(result);
   134→
   135→    // Exit with appropriate code if configured
   136→    if (this.config.exitOnFailure && !passed) {
   137→      process.exit(1);
   138→    }
   139→
   140→    return result;
   141→  }
   142→
   143→  /**
   144→   * Load baseline metrics
   145→   */
   146→  private async loadBaseline(file: string): Promise<void> {
   147→    try {
   148→      const fs = await import('fs/promises');
   149→      const data = await fs.readFile(file, 'utf-8');
   150→      this.baseline = JSON.parse(data);
   151→      console.log(`📊 Loaded baseline from ${file}`);
   152→    } catch (error) {
   153→      console.warn(`⚠️  Could not load baseline: ${error}`);
   154→    }
   155→  }
   156→
   157→  /**
   158→   * Detect performance regressions
   159→   */
   160→  private detectRegressions(result: BenchmarkResult): RegressionReport[] {
   161→    const regressions: RegressionReport[] = [];
   162→
   163→    if (!this.baseline) {
   164→      return regressions;
   165→    }
   166→
   167→    // Check timing precision
   168→    const currentTiming = result.performance.timing.stimulusOnsetJitter;
   169→    const baselineTiming = this.baseline.metrics.timingPrecision;
   170→    const timingChange = ((currentTiming - baselineTiming) / baselineTiming) * 100;
   171→
   172→    if (timingChange > 10) {
   173→      regressions.push({
   174→        metric: 'Timing Precision',
   175→        baseline: baselineTiming,
   176→        current: currentTiming,
   177→        change: timingChange,
   178→        threshold: 10,
   179→        severity: timingChange > 20 ? 'error' : 'warning'
   180→      });
   181→    }
   182→
   183→    // Check FPS
   184→    const currentFPS = result.performance.fps.average;
   185→    const baselineFPS = this.baseline.metrics.avgFPS;
   186→    const fpsChange = ((baselineFPS - currentFPS) / baselineFPS) * 100;
   187→
   188→    if (fpsChange > 5) {
   189→      regressions.push({
   190→        metric: 'Frame Rate',
   191→        baseline: baselineFPS,
   192→        current: currentFPS,
   193→        change: -fpsChange,
   194→        threshold: 5,
   195→        severity: fpsChange > 10 ? 'error' : 'warning'
   196→      });
   197→    }
   198→
   199→    // Check frame variance
   200→    const currentVariance = result.performance.frameVariance.standardDeviation;
   201→    const baselineVariance = this.baseline.metrics.frameVariance;
   202→    const varianceChange = ((currentVariance - baselineVariance) / baselineVariance) * 100;
   203→
   204→    if (varianceChange > 15) {
   205→      regressions.push({
   206→        metric: 'Frame Variance',
   207→        baseline: baselineVariance,
   208→        current: currentVariance,
   209→        change: varianceChange,
   210→        threshold: 15,
   211→        severity: varianceChange > 30 ? 'error' : 'warning'
   212→      });
   213→    }
   214→
   215→    // Check memory usage
   216→    const currentMemory = result.performance.memory.heapUsed;
   217→    const baselineMemory = this.baseline.metrics.memoryUsage;
   218→    const memoryChange = ((currentMemory - baselineMemory) / baselineMemory) * 100;
   219→
   220→    if (memoryChange > 20) {
   221→      regressions.push({
   222→        metric: 'Memory Usage',
   223→        baseline: baselineMemory,
   224→        current: currentMemory,
   225→        change: memoryChange,
   226→        threshold: 20,
   227→        severity: memoryChange > 50 ? 'error' : 'warning'
   228→      });
   229→    }
   230→
   231→    return regressions;
   232→  }
   233→
   234→  /**
   235→   * Evaluate overall pass/fail
   236→   */
   237→  private evaluateResults(
   238→    benchmark: BenchmarkResult,
   239→    videoFrame: VideoFrameValidationResult,
   240→    regressions: RegressionReport[]
   241→  ): boolean {
   242→    // Check threshold violations
   243→    const timingMet = benchmark.performance.timing.stimulusOnsetJitter <= this.config.thresholds.timingPrecision;
   244→    const fpsMet = benchmark.performance.fps.percentiles.p95 >= this.config.thresholds.fpsMinimum;
   245→    const varianceMet = benchmark.performance.frameVariance.standardDeviation <= this.config.thresholds.frameVariance;
   246→    const memoryMet = benchmark.performance.memory.heapUsed <= this.config.thresholds.memoryLimit;
   247→
   248→    // Check for critical regressions
   249→    const hasCriticalRegression = regressions.some(r => r.severity === 'error');
   250→
   251→    // Video frame callback should have high consistency if supported
   252→    const videoFrameMet = !videoFrame.supported || videoFrame.consistency >= 90;
   253→
   254→    return timingMet && fpsMet && varianceMet && memoryMet && !hasCriticalRegression && videoFrameMet;
   255→  }
   256→
   257→  /**
   258→   * Generate comprehensive report
   259→   */
   260→  private generateReport(
   261→    benchmark: BenchmarkResult,
   262→    videoFrame: VideoFrameValidationResult,
   263→    regressions: RegressionReport[]
   264→  ): string {
   265→    const passed = this.evaluateResults(benchmark, videoFrame, regressions);
   266→
   267→    let report = `# CI Timing Validation Report
   268→
   269→**Status**: ${passed ? '✅ PASSED' : '❌ FAILED'}
   270→**Date**: ${new Date().toISOString()}
   271→**Environment**: ${process.env.CI ? 'CI' : 'Local'} (${process.platform})
   272→
   273→## Summary
   274→
   275→### Timing Precision
   276→- **Stimulus Onset Jitter**: ${benchmark.performance.timing.stimulusOnsetJitter.toFixed(2)}ms (threshold: ${this.config.thresholds.timingPrecision}ms)
   277→- **Status**: ${benchmark.performance.timing.stimulusOnsetJitter <= this.config.thresholds.timingPrecision ? '✅' : '❌'}
   278→
