#!/usr/bin/env node

/**
 * CLI for Hardware Timing Validation
 * 
 * Usage: npx @psyforge/validation [options]
 */

import { CIValidator } from './ci-integration';
import { HardwareBenchmark } from './hardware-benchmark';
import { VideoFrameValidator } from './video-frame-validation';

interface CLIOptions {
  mode: 'full' | 'benchmark' | 'video' | 'ci';
  output: 'json' | 'markdown' | 'junit';
  baseline?: string;
  saveBaseline?: string;
  exitOnFailure: boolean;
}

async function parseArgs(): Promise<CLIOptions> {
  const args = process.argv.slice(2);
  const options: CLIOptions = {
    mode: 'full',
    output: 'markdown',
    exitOnFailure: true
  };

  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case '--mode':
      case '-m':
        options.mode = args[++i] as CLIOptions['mode'];
        break;

      case '--output':
      case '-o':
        options.output = args[++i] as CLIOptions['output'];
        break;

      case '--baseline':
      case '-b':
        options.baseline = args[++i];
        break;

      case '--save-baseline':
      case '-s':
        options.saveBaseline = args[++i];
        break;

      case '--no-exit':
        options.exitOnFailure = false;
        break;

      case '--help':
      case '-h':
        printHelp();
        process.exit(0);
    }
  }

  return options;
}

function printHelp(): void {
  console.log(`
Psycho-Forge Hardware Timing Validation

Usage: npx @psyforge/validation [options]

Options:
  -m, --mode <mode>         Validation mode: full, benchmark, video, ci (default: full)
  -o, --output <format>     Output format: json, markdown, junit (default: markdown)
  -b, --baseline <file>     Baseline file for regression detection
  -s, --save-baseline <file> Save results as new baseline
  --no-exit                 Don't exit with error code on failure
  -h, --help               Show this help message

Examples:
  # Run full validation
  npx @psyforge/validation

  # Run CI validation with baseline
  npx @psyforge/validation --mode ci --baseline baseline.json

  # Save new baseline
  npx @psyforge/validation --save-baseline baseline.json

  # Output JSON for processing
  npx @psyforge/validation --output json > results.json
`);
}

async function runValidation(options: CLIOptions): Promise<void> {
  console.log('🚀 Psycho-Forge Hardware Timing Validation\n');

  try {
    switch (options.mode) {
      case 'benchmark':
        await runBenchmarkOnly(options);
        break;

      case 'video':
        await runVideoOnly(options);
        break;

      case 'ci':
        await runCIValidation(options);
        break;

      case 'full':
      default:
        await runFullValidation(options);
        break;
    }
  } catch (error) {
    console.error('❌ Validation failed:', error);
    if (options.exitOnFailure) {
      process.exit(1);
    }
  }
}

async function runBenchmarkOnly(options: CLIOptions): Promise<void> {
  const benchmark = new HardwareBenchmark();
  const result = await benchmark.runFullBenchmark();

  if (options.output === 'json') {
    console.log(JSON.stringify(result, null, 2));
  } else {
    console.log(benchmark.generateReport());
  }

  if (!result.validation.passed && options.exitOnFailure) {
    process.exit(1);
  }
}

async function runVideoOnly(options: CLIOptions): Promise<void> {
  const validator = new VideoFrameValidator();
  const result = await validator.validate();

  if (options.output === 'json') {
    console.log(JSON.stringify(result, null, 2));
  } else {
    console.log(validator.generateReport(result));
  }

  if (!result.supported && options.exitOnFailure) {
    process.exit(1);
  }
}

async function runCIValidation(options: CLIOptions): Promise<void> {
  const validator = new CIValidator({
    baselineFile: options.baseline,
    outputFormat: options.output,
    exitOnFailure: options.exitOnFailure
  });

  const result = await validator.runValidation();

  if (options.saveBaseline) {
    await validator.saveBaseline(result, options.saveBaseline);
  }
}

async function runFullValidation(options: CLIOptions): Promise<void> {
  // Run hardware benchmark
  console.log('📊 Running hardware benchmark...\n');
  const benchmark = new HardwareBenchmark();
  const benchmarkResult = await benchmark.runFullBenchmark();

  // Run video frame validation
  console.log('\n🎥 Running video frame validation...\n');
  const videoValidator = new VideoFrameValidator();
  const videoResult = await videoValidator.validate();

  // Generate combined report
  if (options.output === 'json') {
    console.log(JSON.stringify({
      benchmark: benchmarkResult,
      videoFrame: videoResult
    }, null, 2));
  } else {
    console.log('\n' + benchmark.generateReport());
    console.log('\n' + videoValidator.generateReport(videoResult));

    // Overall summary
    const passed = benchmarkResult.validation.passed && 
                  (!videoResult.supported || videoResult.consistency >= 90);

    console.log(`\n${'='.repeat(60)}`);
    console.log(`Overall Result: ${passed ? '✅ PASSED' : '❌ FAILED'}`);
    console.log(`${'='.repeat(60)}\n`);

    if (!passed && options.exitOnFailure) {
      process.exit(1);
    }
  }

  // Save baseline if requested
  if (options.saveBaseline) {
    const baseline = {
      version: '1.0.0',
      timestamp: Date.now(),
      benchmark: benchmarkResult,
      videoFrame: videoResult
    };

    try {
      const fs = await import('fs/promises');
      await fs.writeFile(options.saveBaseline, JSON.stringify(baseline, null, 2));
      console.log(`✅ Saved baseline to ${options.saveBaseline}`);
    } catch (error) {
      console.error(`❌ Failed to save baseline: ${error}`);
    }
  }
}

// Main execution
(async () => {
  const options = await parseArgs();
  await runValidation(options);
})().catch(error => {
  console.error('Fatal error:', error);
  process.exit(1);
});

