     6→export enum RenderingMode {
     7→  WEBGL2 = 'webgl2',
     8→  WEBGL1 = 'webgl1',
     9→  CANVAS2D = 'canvas2d',
    10→  UNSUPPORTED = 'unsupported'
    11→}
    12→
    13→export interface WebGLCapabilities {
    14→  mode: RenderingMode;
    15→  maxTextureSize: number;
    16→  maxRenderBufferSize: number;
    17→  vertexShaderPrecision: 'highp' | 'mediump' | 'lowp' | null;
