import { describe, it, expect, beforeEach, vi } from 'vitest';
import { WebGLCompatibility, RenderingMode } from '../../src/stimuli/compatibility/WebGLCompatibility';

describe('WebGLCompatibility', () => {
  let originalGetContext: typeof HTMLCanvasElement.prototype.getContext;

  beforeEach(() => {
    // Store original getContext
    originalGetContext = HTMLCanvasElement.prototype.getContext;

    // Reset capabilities cache
    (WebGLCompatibility as any).capabilities = null;
  });

  afterEach(() => {
    // Restore original getContext
    HTMLCanvasElement.prototype.getContext = originalGetContext;
  });

  describe('detectCapabilities', () => {
    it('should detect WebGL2 support when available', () => {
      const mockGL2 = createMockWebGLContext();
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === 'webgl2') return mockGL2;
        return null;
      });

      const capabilities = WebGLCompatibility.detectCapabilities();

      expect(capabilities.mode).toBe(RenderingMode.WEBGL2);
      expect(capabilities.maxTextureSize).toBe(16384);
      expect(capabilities.warnings).toHaveLength(0);
    });

    it('should fallback to WebGL1 when WebGL2 not available', () => {
      const mockGL1 = createMockWebGLContext();
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === 'webgl' || contextType === 'experimental-webgl') return mockGL1;
        return null;
      });

      const capabilities = WebGLCompatibility.detectCapabilities();

      expect(capabilities.mode).toBe(RenderingMode.WEBGL1);
      expect(capabilities.warnings).toContain('WebGL1 only - performance may be limited compared to WebGL2');
    });

    it('should fallback to Canvas2D when no WebGL available', () => {
      const mockCanvas2D = createMockCanvas2DContext();
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === '2d') return mockCanvas2D;
        return null;
      });

      const capabilities = WebGLCompatibility.detectCapabilities();

      expect(capabilities.mode).toBe(RenderingMode.CANVAS2D);
      expect(capabilities.warnings).toContain('No WebGL support - using Canvas2D fallback with reduced performance');
      expect(capabilities.warnings).toContain('Timing precision may be affected in Canvas2D mode');
    });

    it('should detect low texture size warning', () => {
      const mockGL = createMockWebGLContext({ maxTextureSize: 1024 });
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === 'webgl2') return mockGL;
        return null;
      });

      const capabilities = WebGLCompatibility.detectCapabilities();

      expect(capabilities.warnings).toContain('Low maximum texture size (1024px) - large stimuli may not render');
    });

    it('should detect shader precision', () => {
      const mockGL = createMockWebGLContext();
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === 'webgl2') return mockGL;
        return null;
      });

      const capabilities = WebGLCompatibility.detectCapabilities();

      expect(capabilities.vertexShaderPrecision).toBe('highp');
      expect(capabilities.fragmentShaderPrecision).toBe('highp');
    });
  });

  describe('hasExtension', () => {
    it('should check for WebGL extensions', () => {
      const mockGL = createMockWebGLContext({
        extensions: ['EXT_color_buffer_float', 'OES_texture_float']
      });
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === 'webgl2') return mockGL;
        return null;
      });

      WebGLCompatibility.detectCapabilities();

      expect(WebGLCompatibility.hasExtension('EXT_color_buffer_float')).toBe(true);
      expect(WebGLCompatibility.hasExtension('OES_texture_float')).toBe(true);
      expect(WebGLCompatibility.hasExtension('WEBGL_draw_buffers')).toBe(false);
    });
  });

  describe('getRecommendedSettings', () => {
    it('should return optimal settings for WebGL2', () => {
      const mockGL = createMockWebGLContext();
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === 'webgl2') return mockGL;
        return null;
      });

      WebGLCompatibility.detectCapabilities();
      const settings = WebGLCompatibility.getRecommendedSettings();

      expect(settings.antialias).toBe(true);
      expect(settings.powerPreference).toBe('high-performance');
      expect(settings.resolution).toBe(window.devicePixelRatio || 1);
    });

    it('should return limited settings for Canvas2D', () => {
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === '2d') return createMockCanvas2DContext();
        return null;
      });

      WebGLCompatibility.detectCapabilities();
      const settings = WebGLCompatibility.getRecommendedSettings();

      expect(settings.antialias).toBe(false);
      expect(settings.powerPreference).toBe('low-power');
      expect(settings.resolution).toBe(1);
    });
  });

  describe('canAchieveTimingPrecision', () => {
    it('should return true for 2ms with WebGL2', () => {
      const mockGL = createMockWebGLContext();
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === 'webgl2') return mockGL;
        return null;
      });

      WebGLCompatibility.detectCapabilities();

      expect(WebGLCompatibility.canAchieveTimingPrecision(2)).toBe(true);
      expect(WebGLCompatibility.canAchieveTimingPrecision(5)).toBe(true);
      expect(WebGLCompatibility.canAchieveTimingPrecision(16)).toBe(true);
    });

    it('should return false for 2ms with Canvas2D', () => {
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === '2d') return createMockCanvas2DContext();
        return null;
      });

      WebGLCompatibility.detectCapabilities();

      expect(WebGLCompatibility.canAchieveTimingPrecision(2)).toBe(false);
      expect(WebGLCompatibility.canAchieveTimingPrecision(5)).toBe(false);
      expect(WebGLCompatibility.canAchieveTimingPrecision(16)).toBe(true);
    });
  });

  describe('getCompatibilityReport', () => {
    it('should generate comprehensive report', () => {
      const mockGL = createMockWebGLContext();
      HTMLCanvasElement.prototype.getContext = vi.fn((contextType: string) => {
        if (contextType === 'webgl2') return mockGL;
        return null;
      });

      WebGLCompatibility.detectCapabilities();
      const report = WebGLCompatibility.getCompatibilityReport();

      expect(report).toContain('WebGL Compatibility Report');
      expect(report).toContain('Rendering Mode: webgl2');
      expect(report).toContain('Max Texture Size: 16384px');
      expect(report).toContain('Vertex Shader Precision: highp');
    });
  });
});

// Helper functions
function createMockWebGLContext(options: any = {}) {
  const extensions = options.extensions || ['EXT_color_buffer_float'];

  return {
    MAX_TEXTURE_SIZE: 0x0D33,
    MAX_RENDERBUFFER_SIZE: 0x84E8,
    VERTEX_SHADER: 0x8B31,
    FRAGMENT_SHADER: 0x8B30,
    HIGH_FLOAT: 0x8DF2,
    MEDIUM_FLOAT: 0x8DF1,

    getParameter: vi.fn((param: number) => {
      if (param === 0x0D33) return options.maxTextureSize || 16384;
      if (param === 0x84E8) return options.maxRenderBufferSize || 16384;
      return 0;
    }),

    getShaderPrecisionFormat: vi.fn((shaderType: number, precisionType: number) => {
      if (precisionType === 0x8DF2) { // HIGH_FLOAT
        return options.lowPrecision ? { precision: 0 } : { precision: 23 };
      }
      return { precision: 10 };
    }),

    getSupportedExtensions: vi.fn(() => extensions),

    getExtension: vi.fn((name: string) => {
      return extensions.includes(name) ? {} : null;
    })
  };
}

function createMockCanvas2DContext() {
  return {
    fillRect: vi.fn(),
    strokeRect: vi.fn(),
    clearRect: vi.fn()
  };
}

