/**
 * WebGL Compatibility Layer
 * Provides feature detection and fallback mechanisms for WebGL support
 */

export enum RenderingMode {
  WEBGL2 = 'webgl2',
  WEBGL1 = 'webgl1',
  CANVAS2D = 'canvas2d',
  UNSUPPORTED = 'unsupported'
}

export interface WebGLCapabilities {
  mode: RenderingMode;
  maxTextureSize: number;
  maxRenderBufferSize: number;
  vertexShaderPrecision: 'highp' | 'mediump' | 'lowp' | null;
  fragmentShaderPrecision: 'highp' | 'mediump' | 'lowp' | null;
  extensions: string[];
  warnings: string[];
}

export class WebGLCompatibility {
  private static capabilities: WebGLCapabilities | null = null;

  /**
   * Detect WebGL capabilities and determine best rendering mode
   */
  static detectCapabilities(): WebGLCapabilities {
    if (this.capabilities) {
      return this.capabilities;
    }

    const canvas = document.createElement('canvas');
    const warnings: string[] = [];
    let mode = RenderingMode.UNSUPPORTED;
    let maxTextureSize = 0;
    let maxRenderBufferSize = 0;
    let vertexShaderPrecision: 'highp' | 'mediump' | 'lowp' | null = null;
    let fragmentShaderPrecision: 'highp' | 'mediump' | 'lowp' | null = null;
    let extensions: string[] = [];

    // Try WebGL2 first
    let gl = canvas.getContext('webgl2');
    if (gl) {
      mode = RenderingMode.WEBGL2;
      maxTextureSize = gl.getParameter(gl.MAX_TEXTURE_SIZE);
      maxRenderBufferSize = gl.getParameter(gl.MAX_RENDERBUFFER_SIZE);

      // Check shader precision
      const vertexHighp = gl.getShaderPrecisionFormat(gl.VERTEX_SHADER, gl.HIGH_FLOAT);
      const fragmentHighp = gl.getShaderPrecisionFormat(gl.FRAGMENT_SHADER, gl.HIGH_FLOAT);

      if (vertexHighp && vertexHighp.precision > 0) {
        vertexShaderPrecision = 'highp';
      } else {
        const vertexMediump = gl.getShaderPrecisionFormat(gl.VERTEX_SHADER, gl.MEDIUM_FLOAT);
        vertexShaderPrecision = vertexMediump && vertexMediump.precision > 0 ? 'mediump' : 'lowp';
      }

      if (fragmentHighp && fragmentHighp.precision > 0) {
        fragmentShaderPrecision = 'highp';
      } else {
        const fragmentMediump = gl.getShaderPrecisionFormat(gl.FRAGMENT_SHADER, gl.MEDIUM_FLOAT);
        fragmentShaderPrecision = fragmentMediump && fragmentMediump.precision > 0 ? 'mediump' : 'lowp';
      }

      // Get supported extensions
      extensions = gl.getSupportedExtensions() || [];

      // Check for important WebGL2 features
      if (!gl.getExtension('EXT_color_buffer_float')) {
        warnings.push('Float color buffers not supported - some effects may be limited');
      }

    } else {
      // Try WebGL1
      gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');

      if (gl) {
        mode = RenderingMode.WEBGL1;
        maxTextureSize = gl.getParameter(gl.MAX_TEXTURE_SIZE);
        maxRenderBufferSize = gl.getParameter(gl.MAX_RENDERBUFFER_SIZE);

        // Check shader precision
        const vertexHighp = gl.getShaderPrecisionFormat(gl.VERTEX_SHADER, gl.HIGH_FLOAT);
        const fragmentHighp = gl.getShaderPrecisionFormat(gl.FRAGMENT_SHADER, gl.HIGH_FLOAT);

        if (vertexHighp && vertexHighp.precision > 0) {
          vertexShaderPrecision = 'highp';
        } else {
          const vertexMediump = gl.getShaderPrecisionFormat(gl.VERTEX_SHADER, gl.MEDIUM_FLOAT);
          vertexShaderPrecision = vertexMediump && vertexMediump.precision > 0 ? 'mediump' : 'lowp';
        }

        if (fragmentHighp && fragmentHighp.precision > 0) {
          fragmentShaderPrecision = 'highp';
        } else {
          const fragmentMediump = gl.getShaderPrecisionFormat(gl.FRAGMENT_SHADER, gl.MEDIUM_FLOAT);
          fragmentShaderPrecision = fragmentMediump && fragmentMediump.precision > 0 ? 'mediump' : 'lowp';

