/**
 * Canvas2D Fallback Renderer
 * Provides basic rendering capabilities when WebGL is not available
 */

import type { TimelineContext } from '../../core/Timeline.js';

export interface Canvas2DStimulus {
  id: string;
  type: 'text' | 'image' | 'shape';
  x: number;
  y: number;
  width?: number;
  height?: number;
  rotation?: number;
  alpha?: number;
  visible?: boolean;
  data: any;
}

export class Canvas2DFallbackRenderer {
  private canvas: HTMLCanvasElement;
  private ctx: CanvasRenderingContext2D;
  private stimuli: Map<string, Canvas2DStimulus> = new Map();
  private backgroundColor: string = '#000000';
  private animationFrameId: number | null = null;
  private isRunning: boolean = false;

  constructor(canvas?: HTMLCanvasElement) {
    this.canvas = canvas || document.createElement('canvas');
    const ctx = this.canvas.getContext('2d');

    if (!ctx) {
      throw new Error('Canvas 2D context not available');
    }

    this.ctx = ctx;
    this.setupCanvas();
  }

  private setupCanvas(): void {
    if (!this.canvas.parentElement) {
      this.canvas.id = 'psyforge-canvas2d-fallback';
      this.canvas.style.position = 'fixed';
      this.canvas.style.top = '0';
      this.canvas.style.left = '0';
      this.canvas.style.width = '100%';
      this.canvas.style.height = '100%';
      this.canvas.style.zIndex = '1000';
      document.body.appendChild(this.canvas);
    }

    this.resize();
    window.addEventListener('resize', () => this.resize());
  }

  private resize(): void {
    const dpr = window.devicePixelRatio || 1;
    this.canvas.width = window.innerWidth * dpr;
    this.canvas.height = window.innerHeight * dpr;
    this.ctx.scale(dpr, dpr);
    this.canvas.style.width = window.innerWidth + 'px';
    this.canvas.style.height = window.innerHeight + 'px';
  }

  /**
   * Start the rendering loop
   */
  start(): void {
    if (this.isRunning) return;

    this.isRunning = true;
    this.render();
  }

  /**
   * Stop the rendering loop
   */
  stop(): void {
    this.isRunning = false;
    if (this.animationFrameId !== null) {
      cancelAnimationFrame(this.animationFrameId);
      this.animationFrameId = null;
    }
  }

  /**
   * Main render loop
   */
  private render = (): void => {
    if (!this.isRunning) return;

    // Clear canvas
    this.ctx.fillStyle = this.backgroundColor;
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);

    // Render all stimuli
    const sortedStimuli = Array.from(this.stimuli.values()).sort((a, b) => {
      // Sort by z-index if available, otherwise by insertion order
      return 0;
    });

    for (const stimulus of sortedStimuli) {
      if (!stimulus.visible) continue;

      this.ctx.save();

      // Apply transformations
      this.ctx.globalAlpha = stimulus.alpha ?? 1;
      this.ctx.translate(stimulus.x, stimulus.y);

      if (stimulus.rotation) {
        this.ctx.rotate(stimulus.rotation);
      }

      // Render based on type
      switch (stimulus.type) {
        case 'text':
          this.renderText(stimulus);
          break;
        case 'image':
          this.renderImage(stimulus);
          break;
        case 'shape':
          this.renderShape(stimulus);
          break;
      }

      this.ctx.restore();
    }

    this.animationFrameId = requestAnimationFrame(this.render);
  };

  private renderText(stimulus: Canvas2DStimulus): void {
    const data = stimulus.data;

    this.ctx.font = `${data.fontSize || 24}px ${data.fontFamily || 'Arial'}`;
    this.ctx.fillStyle = data.color || '#FFFFFF';
    this.ctx.textAlign = data.align || 'center';
    this.ctx.textBaseline = data.baseline || 'middle';

    if (data.shadow) {
      this.ctx.shadowColor = data.shadow.color || 'rgba(0,0,0,0.5)';
      this.ctx.shadowBlur = data.shadow.blur || 4;
      this.ctx.shadowOffsetX = data.shadow.offsetX || 2;
      this.ctx.shadowOffsetY = data.shadow.offsetY || 2;
    }

    this.ctx.fillText(data.text, 0, 0);

